import { NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { processCampaignWorkflow } from '@/lib/workflow-engine'

// Now an async orchestrator endpoint
export async function POST(request: Request) {
    try {
        const data = await request.json()
        const { campaignId } = data

        if (!campaignId) {
            return NextResponse.json(
                { error: 'Missing campaignId' },
                { status: 400 }
            )
        }

        // 1. Fire and Forget the workflow engine (Asynchronous)
        // NOTE: In production serverless environments (like Vercel functions),
        // you would typically use an Upstash Queue or similar here because 
        // dangling promises are killed after the request ends. 
        // However, for Node/Local/NextJS dev servers, this simulates it perfectly.
        processCampaignWorkflow(campaignId).catch(console.error);

        // 3. Return immediately to unblock client
        return NextResponse.json({
            success: true,
            status: 'ANALYZING',
            message: 'Workflow started'
        }, { status: 202 })

    } catch (error) {
        console.error('Error starting analysis workflow:', error)
        return NextResponse.json(
            { error: 'Failed to start analysis workflow' },
            { status: 500 }
        )
    }
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { getSessionUser } from '@/lib/auth'

export async function GET(
    request: Request,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const user = await getSessionUser()
        const { id } = await params

        // Fetch campaign with ALL analysis runs (for trend), workflow logs, and decisions
        const campaign = await prisma.campaign.findUnique({
            where: {
                id,
                userId: user.id
            },
            include: {
                analysisRuns: {
                    orderBy: { createdAt: 'asc' } // Chronological for charting
                },
                workflowLogs: {
                    orderBy: { createdAt: 'asc' }
                },
                decisions: {
                    orderBy: { createdAt: 'asc' }
                }
            }
        })

        if (!campaign) {
            return NextResponse.json({ error: 'Campaign not found' }, { status: 404 })
        }

        // --- Fatigue Trend Data ---
        const fatigueTrend = campaign.analysisRuns.map((run, index) => ({
            runIndex: index + 1,
            fatigueScore: run.fatigueScore,
            confidenceScore: run.confidenceScore,
            severityLevel: run.severityLevel,
            suggestedAction: run.suggestedAction,
            timestamp: run.createdAt,
        }))

        // Detect rising fatigue trend (3+ consecutive increases)
        let risingStreak = 0
        for (let i = 1; i < fatigueTrend.length; i++) {
            if (fatigueTrend[i].fatigueScore > fatigueTrend[i - 1].fatigueScore) {
                risingStreak++
            } else {
                risingStreak = 0
            }
        }
        const hasFatigueAcceleration = risingStreak >= 2 && fatigueTrend.length >= 3

        // --- Agent Execution Timeline ---
        const agentTimeline = campaign.workflowLogs.map(log => {
            let parsed: Record<string, any> = {}
            try {
                parsed = log.payload ? JSON.parse(log.payload) : {}
            } catch { /* ignore parse errors */ }

            return {
                step: log.step,
                timestamp: log.createdAt,
                payload: parsed,
            }
        })

        // --- Learning Bias Analysis ---
        const allDecisions = campaign.decisions
        const totalDecisions = allDecisions.length

        const pauseDecisions = allDecisions.filter(d => d.actionTaken === 'pause_ad')
        const refreshDecisions = allDecisions.filter(d => d.actionTaken === 'refresh_creative')

        // Find runs that have corresponding decisions
        const runsWithActions = campaign.analysisRuns.map(run => {
            const suggestedAction = run.suggestedAction
            return {
                fatigueScore: run.fatigueScore,
                suggestedAction,
                createdAt: run.createdAt,
            }
        })

        // Calculate average fatigue at pause vs continue
        // We pair decisions with the closest preceding analysis run
        let avgFatigueAtPause = 0
        let avgFatigueAtContinue = 0
        let pauseWithFatigue = 0
        let continueWithFatigue = 0

        for (const decision of allDecisions) {
            // Find the latest run before this decision
            const precedingRun = campaign.analysisRuns
                .filter(r => new Date(r.createdAt) <= new Date(decision.createdAt))
                .pop()

            if (precedingRun) {
                if (decision.actionTaken === 'pause_ad') {
                    avgFatigueAtPause += precedingRun.fatigueScore
                    pauseWithFatigue++
                } else {
                    avgFatigueAtContinue += precedingRun.fatigueScore
                    continueWithFatigue++
                }
            }
        }

        avgFatigueAtPause = pauseWithFatigue > 0 ? Math.round(avgFatigueAtPause / pauseWithFatigue) : 0
        avgFatigueAtContinue = continueWithFatigue > 0 ? Math.round(avgFatigueAtContinue / continueWithFatigue) : 0

        // --- Decision Consistency ---
        // Compare system suggestion vs user action
        let overrideCount = 0
        let alignedCount = 0

        for (const decision of allDecisions) {
            const precedingRun = campaign.analysisRuns
                .filter(r => new Date(r.createdAt) <= new Date(decision.createdAt))
                .pop()

            if (precedingRun) {
                const systemAction = precedingRun.suggestedAction
                const userAction = decision.actionTaken

                // Map user actions to system action names for comparison
                const isAligned =
                    (systemAction === 'PAUSE' && userAction === 'pause_ad') ||
                    (systemAction === 'REFRESH' && userAction === 'refresh_creative') ||
                    (systemAction === 'TEST' && userAction === 'refresh_creative') ||
                    (systemAction === 'CONTINUE' && userAction === 'refresh_creative')

                if (isAligned) alignedCount++
                else overrideCount++
            }
        }

        const consistencyScore = totalDecisions > 0
            ? Math.round((alignedCount / totalDecisions) * 100)
            : 100 // No decisions = no disagreements

        // System recommendations vs user choices
        const systemPauseCount = campaign.analysisRuns.filter(r => r.suggestedAction === 'PAUSE').length
        const userIgnoredPause = campaign.analysisRuns.filter(r => {
            if (r.suggestedAction !== 'PAUSE') return false
            // Check if user took a different action after this run
            const followingDecision = allDecisions.find(
                d => new Date(d.createdAt) >= new Date(r.createdAt)
            )
            return followingDecision && followingDecision.actionTaken !== 'pause_ad'
        }).length

        return NextResponse.json({
            campaign: {
                id: campaign.id,
                platform: campaign.platform,
                adType: campaign.adType,
                status: campaign.status,
                createdAt: campaign.createdAt,
                updatedAt: campaign.updatedAt,
            },
            fatigueTrend,
            hasFatigueAcceleration,
            agentTimeline,
            learningBias: {
                totalDecisions,
                pauseCount: pauseDecisions.length,
                refreshCount: refreshDecisions.length,
                avgFatigueAtPause,
                avgFatigueAtContinue,
                overrideRate: totalDecisions > 0 ? Math.round((pauseDecisions.length / totalDecisions) * 100) : 0,
                systemPauseCount,
                userIgnoredPause,
            },
            decisionConsistency: {
                score: consistencyScore,
                totalDecisions,
                alignedCount,
                overrideCount,
            },
            latestRun: campaign.analysisRuns.at(-1) ?? null,
        })

    } catch (error) {
        console.error('Error fetching campaign intelligence:', error)
        return NextResponse.json({ error: 'Failed to fetch intelligence' }, { status: 500 })
    }
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { getSessionUser } from '@/lib/auth'

export async function GET(
    request: Request,
    { params }: { params: Promise<{ id: string }> } // In Next.js 15, params is a Promise
) {
    try {
        const user = await getSessionUser()
        const { id } = await params

        const campaign = await prisma.campaign.findUnique({
            where: {
                id,
                userId: user.id // Ensure user owns the campaign
            },
            include: {
                decisions: {
                    orderBy: { createdAt: 'desc' }
                },
                analysisRuns: {
                    orderBy: { createdAt: 'desc' },
                    take: 1
                },
                workflowLogs: {
                    orderBy: { createdAt: 'desc' }
                }
            }
        })

        if (!campaign) {
            return NextResponse.json({ error: 'Campaign not found' }, { status: 404 })
        }

        // Compute latest run for convenience
        const latestRun = campaign.analysisRuns[0] ?? null
        // Extract completed agent steps for progress tracking
        const completedSteps = campaign.workflowLogs.map(log => log.step)
        const { analysisRuns, workflowLogs, ...campaignData } = campaign as any

        return NextResponse.json({ ...campaignData, latestRun, completedSteps })
    } catch (error) {
        console.error('Error fetching campaign:', error)
        return NextResponse.json({ error: 'Failed to fetch campaign' }, { status: 500 })
    }
}

export async function PUT(
    request: Request,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const user = await getSessionUser()
        const { id } = await params
        const data = await request.json()

        // Verify ownership
        const existing = await prisma.campaign.findUnique({
            where: { id, userId: user.id }
        })

        if (!existing) {
            return NextResponse.json({ error: 'Campaign not found' }, { status: 404 })
        }

        // Determine data to update
        const updateData: any = {
            // Increment version on update automatically
            version: { increment: 1 }
        }

        // Safely update campaign-level fields only
        if (data.status) updateData.status = data.status
        if (data.metrics) updateData.metrics = JSON.stringify(data.metrics)
        if (data.feedback) updateData.feedback = JSON.stringify(data.feedback)

        const updatedCampaign = await prisma.campaign.update({
            where: { id },
            data: updateData
        })

        return NextResponse.json(updatedCampaign)
    } catch (error) {
        console.error('Error updating campaign:', error)
        return NextResponse.json({ error: 'Failed to update campaign' }, { status: 500 })
    }
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { getSessionUser } from '@/lib/auth'

export async function GET() {
    try {
        const user = await getSessionUser()

        // Fetch all campaigns with their latest analysis run and decision history
        const campaigns = await prisma.campaign.findMany({
            where: { userId: user.id },
            include: {
                analysisRuns: {
                    orderBy: { createdAt: 'desc' },
                    take: 1
                },
                decisions: {
                    orderBy: { createdAt: 'desc' }
                }
            },
            orderBy: { updatedAt: 'desc' }
        })

        // Compute aggregate stats
        const totalCampaigns = campaigns.length
        const totalAnalyses = await prisma.analysisRun.count({
            where: {
                campaign: { userId: user.id }
            }
        })

        // Compute stats from latest runs only
        const campaignsWithRuns = campaigns.filter(c => c.analysisRuns.length > 0)
        const latestScores = campaignsWithRuns.map(c => c.analysisRuns[0].fatigueScore)

        const avgFatigue = latestScores.length > 0
            ? latestScores.reduce((sum, s) => sum + s, 0) / latestScores.length
            : 0

        const severeCampaigns = campaignsWithRuns.filter(
            c => c.analysisRuns[0].severityLevel === 'CRITICAL' || c.analysisRuns[0].severityLevel === 'HIGH'
        ).length

        const severityPercent = totalCampaigns > 0
            ? (severeCampaigns / totalCampaigns) * 100
            : 0

        // Calculate user override rate from decision history
        const allDecisions = campaigns.flatMap(c => c.decisions)
        const totalDecisions = allDecisions.length
        const overrideCount = allDecisions.filter(d =>
            d.actionTaken === 'pause_ad'
        ).length
        const overrideRate = totalDecisions > 0
            ? (overrideCount / totalDecisions) * 100
            : 0

        // Build campaign table rows
        const campaignRows = campaigns.map((c: any) => {
            const latestRun = c.analysisRuns?.[0] ?? null
            const { analysisRuns, decisions, ...campaignData } = c
            return {
                ...campaignData,
                latestRun: latestRun ? {
                    id: latestRun.id,
                    fatigueScore: latestRun.fatigueScore,
                    confidenceScore: latestRun.confidenceScore,
                    severityLevel: latestRun.severityLevel,
                    suggestedAction: latestRun.suggestedAction,
                    createdAt: latestRun.createdAt,
                } : null,
                totalDecisions: decisions.length,
                lastDecision: decisions[0]?.actionTaken ?? null,
            }
        })

        return NextResponse.json({
            stats: {
                totalCampaigns,
                totalAnalyses,
                avgFatigue: Math.round(avgFatigue * 10) / 10,
                severeCampaigns,
                severityPercent: Math.round(severityPercent),
                overrideRate: Math.round(overrideRate),
                campaignsWithRuns: campaignsWithRuns.length,
            },
            campaigns: campaignRows
        })

    } catch (error) {
        console.error('Error fetching dashboard:', error)
        return NextResponse.json({ error: 'Failed to fetch dashboard' }, { status: 500 })
    }
}

'use client'

import { useState, useEffect, useRef } from 'react'
import {
    Sparkles,
    Loader2,
    AlertTriangle,
    ArrowLeft,
    TrendingUp,
    TrendingDown,
    Brain,
    Layers,
    Shield,
    Clock,
    Zap,
    ChevronRight,
    Target,
    BarChart3,
    Eye,
    CheckCircle,
} from 'lucide-react'
import {
    Chart as ChartJS,
    CategoryScale,
    LinearScale,
    PointElement,
    LineElement,
    Filler,
    Tooltip as ChartTooltip,
    Legend,
} from 'chart.js'
import { Line } from 'react-chartjs-2'
import { useParams } from 'next/navigation'

// Register Chart.js components
ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Filler, ChartTooltip, Legend)

// ─── Types ──────────────────────────────────────────

interface FatigueTrendPoint {
    runIndex: number
    fatigueScore: number
    confidenceScore: number
    severityLevel: string
    suggestedAction: string
    timestamp: string
}

interface AgentTimelineEntry {
    step: string
    timestamp: string
    payload: Record<string, any>
}

interface LearningBias {
    totalDecisions: number
    pauseCount: number
    refreshCount: number
    avgFatigueAtPause: number
    avgFatigueAtContinue: number
    overrideRate: number
    systemPauseCount: number
    userIgnoredPause: number
}

interface DecisionConsistency {
    score: number
    totalDecisions: number
    alignedCount: number
    overrideCount: number
}

interface IntelligenceData {
    campaign: {
        id: string
        platform: string
        adType: string | null
        status: string
        createdAt: string
        updatedAt: string
    }
    fatigueTrend: FatigueTrendPoint[]
    hasFatigueAcceleration: boolean
    agentTimeline: AgentTimelineEntry[]
    learningBias: LearningBias
    decisionConsistency: DecisionConsistency
    latestRun: any
}

// ─── Agent Progress Types ───────────────────────────

const AGENT_STEPS = [
    'ANALYSIS_AGENT',
    'FATIGUE_AGENT',
    'LEARNING_AGENT',
    'DECISION_AGENT',
    'RECOMMENDATION_AGENT',
] as const

// ─── Helpers ────────────────────────────────────────

function formatTime(ts: string): string {
    return new Date(ts).toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: false,
    })
}

const AGENT_META: Record<string, { label: string; color: string; icon: string; bgColor: string }> = {
    ANALYSIS_AGENT: { label: 'Analysis Agent', color: 'text-cyan-400', icon: '🔍', bgColor: 'bg-cyan-500/10' },
    FATIGUE_AGENT: { label: 'Fatigue Agent', color: 'text-amber-400', icon: '😴', bgColor: 'bg-amber-500/10' },
    LEARNING_AGENT: { label: 'Learning Agent', color: 'text-purple-400', icon: '📚', bgColor: 'bg-purple-500/10' },
    DECISION_AGENT: { label: 'Decision Agent', color: 'text-blue-400', icon: '⚖️', bgColor: 'bg-blue-500/10' },
    RECOMMENDATION_AGENT: { label: 'Recommendation Agent', color: 'text-emerald-400', icon: '💡', bgColor: 'bg-emerald-500/10' },
    WORKFLOW_ERROR: { label: 'Workflow Error', color: 'text-red-400', icon: '❌', bgColor: 'bg-red-500/10' },
}

function summarizePayload(step: string, payload: Record<string, any>): string {
    switch (step) {
        case 'ANALYSIS_AGENT':
            return Object.entries(payload)
                .map(([k, v]) => `${k}=${String(v)}`)
                .join(', ')
        case 'FATIGUE_AGENT':
            return `score=${payload.fatigueScore}, issue="${payload.primaryIssue}"`
        case 'LEARNING_AGENT':
            return `bias ${payload.suggestedConfidenceAdjustment >= 0 ? '+' : ''}${payload.suggestedConfidenceAdjustment}%, overrideRate=${Math.round((payload.historicalOverrideRate || 0) * 100)}%`
        case 'DECISION_AGENT':
            return `${payload.suggestedAction} (severity=${payload.severityLevel}, confidence=${payload.confidenceScore}%)`
        case 'RECOMMENDATION_AGENT':
            if (Array.isArray(payload)) {
                return payload.map(r => r.text?.slice(0, 50) + '...').join(' | ')
            }
            return JSON.stringify(payload).slice(0, 80)
        default:
            return JSON.stringify(payload).slice(0, 100)
    }
}

// ─── Consistency Ring ──────────────────────────────

function ConsistencyRing({ score }: { score: number }) {
    const radius = 56
    const circumference = 2 * Math.PI * radius
    const offset = circumference - (score / 100) * circumference
    const color = score >= 80 ? '#34d399' : score >= 50 ? '#fbbf24' : '#f87171'

    return (
        <div className="relative w-36 h-36">
            <svg className="w-full h-full -rotate-90" viewBox="0 0 128 128">
                <circle cx="64" cy="64" r={radius} fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="8" />
                <circle
                    cx="64" cy="64" r={radius} fill="none"
                    stroke={color} strokeWidth="8" strokeLinecap="round"
                    strokeDasharray={circumference} strokeDashoffset={offset}
                    className="transition-all duration-1000"
                />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-3xl font-bold text-white">{score}%</span>
                <span className="text-[10px] text-gray-500 font-medium uppercase tracking-wider">Alignment</span>
            </div>
        </div>
    )
}

// ─── Agent Progress Component ───────────────────────

function AgentProgressTracker({ campaignId }: { campaignId: string }) {
    const [completedSteps, setCompletedSteps] = useState<string[]>([])
    const [status, setStatus] = useState<string>('ANALYZING')

    useEffect(() => {
        const poll = setInterval(async () => {
            try {
                const res = await fetch(`/api/campaigns/${campaignId}`)
                if (!res.ok) return
                const data = await res.json()
                setCompletedSteps(data.completedSteps || [])
                setStatus(data.status)

                if (data.status !== 'ANALYZING') {
                    clearInterval(poll)
                    // Redirect to full intelligence page after a brief delay
                    if (data.status === 'DECISION_READY' || data.status === 'COMPLETED') {
                        setTimeout(() => window.location.reload(), 1500)
                    }
                }
            } catch { /* ignore */ }
        }, 1000)

        return () => clearInterval(poll)
    }, [campaignId])

    return (
        <div className="min-h-[60vh] flex items-center justify-center">
            <div className="w-full max-w-lg animate-fade-in-up">
                <div className="bg-white/[0.03] border border-white/[0.08] rounded-2xl p-8">
                    {/* Header */}
                    <div className="text-center mb-8">
                        <div className="relative inline-block mb-4">
                            <div className="absolute inset-0 bg-emerald-500/20 rounded-full blur-2xl animate-pulse" />
                            <div className="relative bg-white/5 backdrop-blur-sm border border-white/10 p-4 rounded-2xl">
                                <Loader2 className="h-8 w-8 text-emerald-400 animate-spin" />
                            </div>
                        </div>
                        <h2 className="text-xl font-bold text-white mb-1">Workflow Engine Running</h2>
                        <p className="text-sm text-gray-500">Multi-agent pipeline executing sequentially</p>
                    </div>

                    {/* Agent Steps */}
                    <div className="space-y-2">
                        {AGENT_STEPS.map((step, index) => {
                            const meta = AGENT_META[step]
                            const isCompleted = completedSteps.includes(step)
                            // Current running = first non-completed step
                            const firstIncomplete = AGENT_STEPS.findIndex(s => !completedSteps.includes(s))
                            const isRunning = index === firstIncomplete && status === 'ANALYZING'
                            const isPending = index > firstIncomplete

                            return (
                                <div
                                    key={step}
                                    className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-500 ${isCompleted ? 'bg-emerald-500/5 border border-emerald-500/10' :
                                            isRunning ? 'bg-white/[0.04] border border-white/10' :
                                                'bg-transparent border border-transparent opacity-40'
                                        }`}
                                >
                                    {/* Status Icon */}
                                    <div className="w-8 h-8 flex items-center justify-center flex-shrink-0">
                                        {isCompleted ? (
                                            <CheckCircle className="h-5 w-5 text-emerald-400" />
                                        ) : isRunning ? (
                                            <Loader2 className="h-5 w-5 text-white animate-spin" />
                                        ) : (
                                            <div className="h-5 w-5 border-2 border-gray-700 rounded-full" />
                                        )}
                                    </div>

                                    {/* Agent Icon */}
                                    <span className="text-lg">{meta.icon}</span>

                                    {/* Agent Name */}
                                    <span className={`text-sm font-medium flex-1 ${isCompleted ? 'text-emerald-400' :
                                            isRunning ? 'text-white' :
                                                'text-gray-600'
                                        }`}>
                                        {meta.label}
                                    </span>

                                    {/* Status Label */}
                                    {isCompleted && (
                                        <span className="text-[10px] font-semibold text-emerald-400/70 uppercase tracking-wider">Complete</span>
                                    )}
                                    {isRunning && (
                                        <span className="text-[10px] font-semibold text-amber-400 uppercase tracking-wider animate-pulse">Running</span>
                                    )}
                                </div>
                            )
                        })}
                    </div>

                    {/* Status message */}
                    {status !== 'ANALYZING' && (
                        <div className="mt-6 text-center">
                            <p className="text-emerald-400 font-semibold text-sm">✅ Pipeline complete. Loading results...</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    )
}

// ─── Chart.js Fatigue Trend Chart ──────────────────

function FatigueTrendChart({ data, hasFatigueAcceleration }: { data: FatigueTrendPoint[], hasFatigueAcceleration: boolean }) {
    const chartRef = useRef(null)

    if (data.length < 2) {
        return (
            <div className="flex flex-col items-center justify-center py-12 text-center">
                <BarChart3 className="h-8 w-8 text-gray-600 mb-3" />
                <p className="text-gray-500 text-sm">Need at least 2 analysis runs to show trend.</p>
                <p className="text-gray-600 text-xs mt-1">Re-analyze this campaign to build history.</p>
            </div>
        )
    }

    const labels = data.map(d => `#${d.runIndex}`)

    const chartData = {
        labels,
        datasets: [
            {
                label: 'Fatigue Score',
                data: data.map(d => d.fatigueScore),
                borderColor: '#f59e0b',
                backgroundColor: 'rgba(245, 158, 11, 0.1)',
                fill: true,
                tension: 0.4,
                pointRadius: 5,
                pointBackgroundColor: '#f59e0b',
                pointBorderColor: '#0a0a1a',
                pointBorderWidth: 2,
                pointHoverRadius: 7,
                borderWidth: 2.5,
            },
            {
                label: 'Confidence Score',
                data: data.map(d => d.confidenceScore),
                borderColor: '#6366f1',
                backgroundColor: 'rgba(99, 102, 241, 0.05)',
                fill: true,
                tension: 0.4,
                pointRadius: 3,
                pointBackgroundColor: '#6366f1',
                pointBorderColor: '#0a0a1a',
                pointBorderWidth: 2,
                borderWidth: 2,
                borderDash: [4, 2],
            },
        ],
    }

    const options = {
        responsive: true,
        maintainAspectRatio: false,
        interaction: {
            mode: 'index' as const,
            intersect: false,
        },
        plugins: {
            legend: {
                display: false,
            },
            tooltip: {
                backgroundColor: '#12122a',
                borderColor: 'rgba(255,255,255,0.1)',
                borderWidth: 1,
                padding: 12,
                titleColor: '#9ca3af',
                titleFont: { size: 11, family: 'monospace' },
                bodyColor: '#fff',
                bodyFont: { size: 13 },
                cornerRadius: 12,
                callbacks: {
                    title: (ctx: any) => {
                        const point = data[ctx[0].dataIndex]
                        return `Run #${point.runIndex} · ${new Date(point.timestamp).toLocaleDateString()}`
                    },
                    afterBody: (ctx: any) => {
                        const point = data[ctx[0].dataIndex]
                        return `${point.severityLevel} → ${point.suggestedAction}`
                    },
                },
            },
        },
        scales: {
            x: {
                grid: { color: 'rgba(255,255,255,0.03)' },
                ticks: { color: 'rgba(255,255,255,0.3)', font: { size: 11 } },
